"""Add two integers."""

def add_numbers(a: int, b: int) -> int {
    return a + b;
}

with entry {
    print(add_numbers(2, 3));
}

"""Person object with a greeting method."""

obj Person {
    has name: str,
        age: int = 0;

    def greeting() -> str {
        return f"{self.name} is {self.age}";
    }
}

with entry {
    person = Person(name="Ava", age=31);
    print(person.greeting());
}

"""Collect city names with a walker."""

node City {
    has name: str = "";
}

walker CityCollector {
    has names: list[str] = [];

    can collect with City entry {
        self.names.append(here.name);
        visit [-->][?:City];
    }
}

with entry {
    first = City(name="Paris");
    second = City(name="Lyon");
    root() ++> first;
    first ++> second;
    result = root() spawn CityCollector();
    print(result);
}

"""Choose the higher priority task."""

obj Task {
    has title: str,
        priority: int = 0;
}

def choose_task(left: Task, right: Task) -> str {
    if left.priority >= right.priority {
        return left.title;
    }
    return right.title;
}

with entry {
    a = Task(title="docs", priority=1);
    b = Task(title="tests", priority=3);
    print(choose_task(a, b));
}

"""Aggregate inventory quantities."""

obj Item {
    has name: str,
        quantity: int = 0;
}

def total_quantity(items: list[Item]) -> int {
    total = 0;
    for item in items {
        total += item.quantity;
    }
    return total;
}

with entry {
    items = [Item(name="pen", quantity=2), Item(name="pad", quantity=5)];
    print(total_quantity(items));
}
